import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useBrand } from '../context/BrandContext';

interface FaqItem {
  q: string;
  a: string;
  category: string;
}

const FAQ_DATA: FaqItem[] = [
  // Getting Started
  { category: 'Getting Started', q: 'How do I create an account?', a: 'Click "Sign Up" in the top right corner or navigate to the signup page. You can sign up with your Google account for one-click access, or create an account with your email address.' },
  { category: 'Getting Started', q: 'Is there a free plan?', a: 'Yes! You can use core features for free, including one free use of each teaser tool. Premium tools like Salary Benchmarking, Job Market Heatmap, and Mock Interview with Webcam require a Pro subscription. Free accounts are limited to 5 AI generations per hour.' },
  { category: 'Getting Started', q: 'How do I upgrade to Pro?', a: 'Visit the Pricing page and click "Upgrade to Pro". Payments are processed securely through Stripe. You can manage or cancel your subscription at any time from your Account page.' },
  { category: 'Getting Started', q: 'What browsers are supported?', a: 'TailorMeSwiftly works best on Chrome, Edge, and Safari. The Mock Interview webcam and speech recognition features require Chrome or Edge for full support. Firefox users will see a text input fallback for speech.' },

  // Resume Tailoring
  { category: 'Resume Tailoring', q: 'How does resume tailoring work?', a: 'Paste or upload your resume text, then paste the target job description. Our AI (powered by Google Gemini) analyzes both documents and generates a tailored version of your resume that highlights relevant skills and experience, optimized for ATS (Applicant Tracking Systems).' },
  { category: 'Resume Tailoring', q: 'Can I upload a PDF resume?', a: 'Yes! You can paste text directly, upload a .txt file, or drag and drop a PDF. The tool will extract the text content from your PDF automatically.' },
  { category: 'Resume Tailoring', q: 'How do resume profiles work?', a: 'Resume profiles let you save multiple versions of your resume (e.g., "Software Engineer", "Product Manager"). Switch between profiles instantly from the wizard page. Profiles are stored securely in your account and sync across devices.' },
  { category: 'Resume Tailoring', q: 'What resume templates are available?', a: 'We offer 15 professional templates including Classic, Modern, Minimal, Executive, Creative, and more. Each template applies different formatting, fonts, and accent colors. Premium templates are available for Pro subscribers.' },
  { category: 'Resume Tailoring', q: 'How do I export my tailored resume?', a: 'After generation, use the Export menu to download as PDF, DOCX, or plain text. You can also copy the formatted content to your clipboard.' },

  // AI Tools
  { category: 'AI Tools', q: 'How many AI tools are available?', a: 'TailorMeSwiftly offers 26+ AI-powered career tools organized into categories: document generation (cover letters, pain letters, cold emails), interview prep (mock interview, tech screen, reverse interview), career intelligence (toxic radar, comp decoder, ghosting predictor), and premium analytics (salary benchmarking, job market heatmap, mock interview with webcam).' },
  { category: 'AI Tools', q: 'What is the "teaser" tier?', a: 'Teaser tools give you one free use to try the feature. After your first use, you\'ll need a Pro subscription to continue using them. This lets you experience the full output before committing.' },
  { category: 'AI Tools', q: 'Are the salary figures accurate?', a: 'Salary benchmarking data and job market demand scores are AI-generated estimates based on general market knowledge. They are not sourced from live job board APIs. Use them as directional guidance alongside other research sources like Glassdoor, Levels.fyi, or Blind.' },
  { category: 'AI Tools', q: 'What is the Toxic Culture Radar?', a: 'The Toxic Radar tool analyzes a company name and generates a toxicity assessment including red flags, Glassdoor sentiment analysis, layoff risk, work-life balance indicators, and an overall safety score. All data is AI-generated and should be verified with your own research.' },

  // Mock Interview
  { category: 'Mock Interview', q: 'How does the webcam mock interview work?', a: 'Select your target role, company, and interview type (behavioral, technical, leadership, or mixed). Grant camera and microphone permissions. The AI generates 5-7 interview questions. For each question, answer via speech (auto-transcribed) or text. After each answer, you receive real-time scoring and feedback. At the end, you get an overall score, radar chart breakdown, and improvement tips.' },
  { category: 'Mock Interview', q: 'Is my webcam video recorded or stored?', a: 'No. Your video stream is displayed locally in your browser only. We never record, transmit, or store any video or audio data. Speech-to-text happens in your browser via the Web Speech API; only the text transcript is sent for AI evaluation.' },
  { category: 'Mock Interview', q: 'What if speech recognition doesn\'t work?', a: 'Speech recognition (Web Speech API) works best in Chrome and Edge. If it\'s not supported in your browser, you\'ll see a text input fallback where you can type your answers. The AI evaluation works identically for typed and spoken answers.' },
  { category: 'Mock Interview', q: 'How is my interview performance scored?', a: 'Each answer is evaluated on Relevance, Depth, Structure, Examples, and Overall impression (1-10 scale). After all questions, you receive an aggregate score and letter grade (A+ through F), plus a radar chart visualization of your strengths and areas for improvement.' },

  // Account & Billing
  { category: 'Account & Billing', q: 'How do I cancel my subscription?', a: 'Go to your Account page and click "Manage Subscription". This opens the Stripe customer portal where you can cancel, update payment methods, or change plans. Cancellation takes effect at the end of your current billing period.' },
  { category: 'Account & Billing', q: 'How do I delete my account?', a: 'Go to your Account page and look for the delete account option. This will remove your profile, saved resume profiles, shared links, and all associated data. This action cannot be undone.' },
  { category: 'Account & Billing', q: 'How do I reset my password?', a: 'If you signed up with Google, use your Google account to sign in — there\'s no separate password. If you signed up with email, use the "Forgot Password" link on the login page to receive a reset email.' },

  // Sharing & Collaboration
  { category: 'Sharing', q: 'How do I share my results?', a: 'After generating results, click the "Share" button to create a public link. Anyone with the link can view your results for 30 days. You can copy the link to share via email, Slack, or any messaging app.' },
  { category: 'Sharing', q: 'Can I delete a shared link?', a: 'Shared links expire automatically after 30 days. Currently, you cannot manually delete a shared link before expiry. Avoid sharing links containing sensitive personal information.' },

  // Privacy & Security
  { category: 'Privacy & Security', q: 'Is my resume data stored on your servers?', a: 'Resume and job description content is processed transiently — it\'s sent to the AI for generation and the results are returned to your browser. We do not permanently store your raw resume text unless you explicitly save it as a Resume Profile.' },
  { category: 'Privacy & Security', q: 'Do you use my data to train AI models?', a: 'No. We access Google Gemini through paid API tiers whose terms of service explicitly state that data submitted via the API is not used to train their models.' },
  { category: 'Privacy & Security', q: 'What data do you collect?', a: 'We collect your account info (name, email from Google), tool usage counts (for rate limiting), saved resume profiles (if you create them), shared links, and feedback submissions. See our full Privacy Policy for details.' },

  // Troubleshooting
  { category: 'Troubleshooting', q: 'Why is the AI generation slow?', a: 'AI generation typically takes 5-15 seconds depending on the complexity of the request. Salary benchmarking and mock interview evaluations may take up to 30 seconds. If generation consistently fails, check your internet connection and try again.' },
  { category: 'Troubleshooting', q: 'I hit a rate limit. What do I do?', a: 'Free accounts are limited to 5 AI generations per hour. Pro accounts get 60 per hour. Wait for the hourly window to reset, or upgrade to Pro for higher limits. The rate limit resets every hour on the hour.' },
  { category: 'Troubleshooting', q: 'The app isn\'t loading or looks broken.', a: 'Try clearing your browser cache and refreshing the page (Ctrl+Shift+R or Cmd+Shift+R). If you\'re using a browser extension that blocks JavaScript, disable it for tailormeswiftly.com. Make sure your browser is up to date.' },
];

const CATEGORIES = [...new Set(FAQ_DATA.map(f => f.category))];

export default function HelpPage() {
  const brand = useBrand();
  const [search, setSearch] = useState('');
  const [openIndex, setOpenIndex] = useState<number | null>(null);
  const [activeCategory, setActiveCategory] = useState<string | null>(null);

  const filtered = FAQ_DATA.filter(f => {
    const matchesSearch = !search || f.q.toLowerCase().includes(search.toLowerCase()) || f.a.toLowerCase().includes(search.toLowerCase());
    const matchesCategory = !activeCategory || f.category === activeCategory;
    return matchesSearch && matchesCategory;
  });

  return (
    <div style={{ maxWidth: '780px', margin: '0 auto', padding: '2rem 1.5rem 4rem' }}>
      {/* Header */}
      <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
        <div style={{ width: '52px', height: '52px', borderRadius: '2px', background: brand.primaryColor, display: 'inline-flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontSize: '1.3rem', marginBottom: '1rem' }}>
          <i className="fa-solid fa-circle-question" />
        </div>
        <h1 style={{ fontSize: '1.8rem', margin: '0 0 0.3rem', color: 'var(--text-primary)' }}>Help Center</h1>
        <p style={{ margin: 0, fontSize: '0.88rem', color: 'var(--text-secondary)' }}>Guides, FAQs, and answers for all 26+ career tools</p>
      </div>

      {/* Search */}
      <div style={{ position: 'relative', marginBottom: '1.25rem' }}>
        <i className="fa-solid fa-magnifying-glass" style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-secondary)', fontSize: '0.85rem' }} />
        <input
          value={search}
          onChange={e => { setSearch(e.target.value); setOpenIndex(null); }}
          placeholder="Search FAQs..."
          style={{ width: '100%', paddingLeft: '2.5rem' }}
        />
      </div>

      {/* Category Pills */}
      <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.4rem', marginBottom: '1.5rem' }}>
        <button
          onClick={() => { setActiveCategory(null); setOpenIndex(null); }}
          className={`btn ${!activeCategory ? 'secondary-btn' : 'ghost-btn'}`}
          style={{ padding: '0.35rem 0.85rem', fontSize: '0.78rem' }}
        >
          All
        </button>
        {CATEGORIES.map(cat => (
          <button
            key={cat}
            onClick={() => { setActiveCategory(activeCategory === cat ? null : cat); setOpenIndex(null); }}
            className={`btn ${activeCategory === cat ? 'secondary-btn' : 'ghost-btn'}`}
            style={{ padding: '0.35rem 0.85rem', fontSize: '0.78rem' }}
          >
            {cat}
          </button>
        ))}
      </div>

      {/* FAQ List */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
        {filtered.length === 0 && (
          <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--text-secondary)', fontSize: '0.88rem' }}>
            <i className="fa-solid fa-face-meh" style={{ fontSize: '1.5rem', marginBottom: '0.5rem', display: 'block' }} />
            No results found for "{search}". Try a different search term or <Link to="/feedback" style={{ color: brand.primaryColor }}>contact us</Link>.
          </div>
        )}

        {filtered.map((faq, i) => {
          const isOpen = openIndex === i;
          return (
            <div
              key={i}
              className="glass-panel"
              style={{ overflow: 'hidden' }}
            >
              <button
                onClick={() => setOpenIndex(isOpen ? null : i)}
                style={{ width: '100%', padding: '0.85rem 1rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '0.75rem', background: 'transparent', border: 'none', cursor: 'pointer', textAlign: 'left' }}
              >
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.65rem', flex: 1 }}>
                  <i className="fa-solid fa-circle-question" style={{ color: brand.primaryColor, fontSize: '0.8rem', flexShrink: 0 }} />
                  <span style={{ fontSize: '0.88rem', fontWeight: 600, color: 'var(--text-primary)' }}>{faq.q}</span>
                </div>
                <i className={`fa-solid fa-chevron-${isOpen ? 'up' : 'down'}`} style={{ color: 'var(--text-secondary)', fontSize: '0.7rem', flexShrink: 0 }} />
              </button>

              {isOpen && (
                <div style={{ padding: '0 1rem 1rem 2.65rem', fontSize: '0.85rem', color: 'var(--text-secondary)', lineHeight: 1.7 }}>
                  {faq.a}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Contact CTA */}
      <div className="asym-card" style={{ textAlign: 'center', marginTop: '2.5rem', padding: '1.5rem' }}>
        <p style={{ fontSize: '0.92rem', fontWeight: 600, color: 'var(--text-primary)', margin: '0 0 0.3rem' }}>Still need help?</p>
        <p style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', margin: '0 0 1rem' }}>We read every message and typically respond within 24 hours.</p>
        <Link to="/feedback" className="btn secondary-btn" style={{ display: 'inline-flex', alignItems: 'center', gap: '0.4rem', padding: '0.6rem 1.25rem', textDecoration: 'none' }}>
          <i className="fa-solid fa-comment-dots" />
          Send Feedback
        </Link>
      </div>
    </div>
  );
}
